// Helper functions to query family data

export const getFamilyMemberById = (id: string): FamilyMember | undefined => {
  return groomFamilyMembers.find(member => member.id === id);
};

export const getFamilyMembersByName = (name: string): FamilyMember[] => {
  return groomFamilyMembers.filter(member => 
    member.name.toLowerCase().includes(name.toLowerCase())
  );
};

export const getChildren = (parentId: string): FamilyMember[] => {
  return groomFamilyMembers.filter(member => 
    member.father === parentId || member.mother === parentId
  );
};

export const getSpouse = (memberId: string): FamilyMember | undefined => {
  const member = getFamilyMemberById(memberId);
  if (!member || !member.spouse) return undefined;
  return getFamilyMemberById(member.spouse);
};

export const getSiblings = (memberId: string): FamilyMember[] => {
  const member = getFamilyMemberById(memberId);
  if (!member) return [];
  
  return groomFamilyMembers.filter(m => 
    m.id !== memberId && 
    ((member.father && m.father === member.father) || 
     (member.mother && m.mother === member.mother))
  );
};

export const getParents = (memberId: string): { father?: FamilyMember; mother?: FamilyMember } => {
  const member = getFamilyMemberById(memberId);
  if (!member) return {};
  
  return {
    father: member.father ? getFamilyMemberById(member.father) : undefined,
    mother: member.mother ? getFamilyMemberById(member.mother) : undefined,
  };
};
